class Solution:
    def maxStability(self, n: int, edges: List[List[int]], k: int) -> int:
        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            root_x, root_y = find(x), find(y)
            if root_x != root_y:
                parent[root_x] = root_y
                return True
            return False

        edges.sort(key=lambda x: x[2])
        parent = list(range(n))
        rank = [0] * n
        must_edges = [edge for edge in edges if edge[3] == 1]
        optional_edges = [edge for edge in edges if edge[3] == 0]
        must_edges.sort(key=lambda x: x[2])
        optional_edges.sort(key=lambda x: x[2])

        for u, v, s, must in must_edges:
            union(u, v)

        if len(set(find(i) for i in range(n))) != 1:
            return -1

        for u, v, s, must in must_edges:
            edges.remove([u, v, s, must])

        edges = optional_edges
        edges.sort(key=lambda x: x[2])

        res = float('inf')
        for s in range(1, 10**5 + 1):
            parent = list(range(n))
            rank = [0] * n
            count = 0
            for u, v, strength, must in edges:
                if strength >= s:
                    if union(u, v):
                        count += 1
                elif strength * 2 >= s and k > 0:
                    if union(u, v):
                        count += 1
                        k -= 1
            if count == n - 1:
                res = min(res, s)
        return res if res != float('inf') else -1
